const YEARLY_VARIABLE = 120000; // dummy value
const MONTHLY_VARIABLE = YEARLY_VARIABLE / 12;
const BASE_REWARD = MONTHLY_VARIABLE * 0.01; // 1%

const output = [];

for (const item of $input.all()) {
  const { task_id, user_id, hours_difference } = item.json;

  let multiplier = 0;
  let reason = '';

  if (hours_difference >= 12) {
    multiplier = 1.05;
    reason = 'Completed 12 hours before deadline';
  } else if (hours_difference >= 0) {
    multiplier = 1.0;
    reason = 'Completed on time';
  } else if (hours_difference >= -12) {
    multiplier = 0.75;
    reason = 'Completed within 12 hours after deadline';
  } else if (hours_difference >= -24) {
    multiplier = 0.5;
    reason = 'Completed within 24 hours after deadline';
  } else {
    continue; // no reward
  }

  const reward_amount = Math.round(BASE_REWARD * multiplier);

  output.push({
    json: {
      task_id,
      user_id,
      reward_amount,
      multiplier,
      reason
    }
  });
}

return output;
